import{_ as a,c as e,o as n,ag as o}from"./chunks/framework.B-XtCDNB.js";const u=JSON.parse('{"title":"Version Binding","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities/version-binding.md","filePath":"capabilities/version-binding.md"}'),l={name:"capabilities/version-binding.md"};function t(i,s,p,r,c,h){return n(),e("div",null,[...s[0]||(s[0]=[o(`<h1 id="version-binding" tabindex="-1">Version Binding <a class="header-anchor" href="#version-binding" aria-label="Permalink to &quot;Version Binding&quot;">​</a></h1><p>Version binding lets a query state the relation versions it expects.</p><p>That makes it a schema-contract feature.</p><p>It is especially useful when:</p><ul><li>an application was written against a specific table version</li><li>you want queries to fail fast when storage no longer matches that expectation</li><li>you want joins to assert that both sides of the query still satisfy the version assumptions they were written against</li></ul><h2 id="basic-form" tabindex="-1">Basic form <a class="header-anchor" href="#basic-form" aria-label="Permalink to &quot;Basic form&quot;">​</a></h2><p>Version binding is attached directly to relation references:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#89DDFF;"> *</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#BABED8;"> public.users@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">3</span></span></code></pre></div><p>That query is saying:</p><blockquote><p>&quot;Run this query only if <code>public.users</code> satisfies the version spec <code>=3</code>.&quot;</p></blockquote><h2 id="version-spec-operators" tabindex="-1">Version spec operators <a class="header-anchor" href="#version-spec-operators" aria-label="Permalink to &quot;Version spec operators&quot;">​</a></h2><p>Common forms include:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">public.users@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">3</span></span>
<span class="line"><span style="color:#BABED8;">public.users@</span><span style="color:#89DDFF;">&lt;</span><span style="color:#F78C6C;">3</span></span>
<span class="line"><span style="color:#BABED8;">public.users@</span><span style="color:#89DDFF;">&gt;</span><span style="color:#F78C6C;">4</span></span>
<span class="line"><span style="color:#BABED8;">public.users@</span><span style="color:#89DDFF;">&lt;=</span><span style="color:#F78C6C;">3</span></span>
<span class="line"><span style="color:#BABED8;">public.users@</span><span style="color:#89DDFF;">&gt;=</span><span style="color:#F78C6C;">4</span></span>
<span class="line"><span style="color:#BABED8;">public.users@</span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;">3_4</span></span></code></pre></div><p>Those forms are part of the parser surface and are exercised in tests.</p><h2 id="join-example" tabindex="-1">Join example <a class="header-anchor" href="#join-example" aria-label="Permalink to &quot;Join example&quot;">​</a></h2><p>Version binding becomes especially valuable when multiple relations participate in a query.</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span></span>
<span class="line"><span style="color:#BABED8;">  a.id,</span></span>
<span class="line"><span style="color:#BABED8;">  b.name</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#BABED8;"> public.vja@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">1</span><span style="color:#F78C6C;"> AS</span><span style="color:#BABED8;"> a</span></span>
<span class="line"><span style="color:#F78C6C;">LEFT JOIN</span><span style="color:#BABED8;"> public.vjb@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">1</span><span style="color:#F78C6C;"> AS</span><span style="color:#BABED8;"> b</span></span>
<span class="line"><span style="color:#F78C6C;">  ON</span><span style="color:#BABED8;"> a.rel </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> b.id</span></span></code></pre></div><p>How to read this:</p><ul><li>the query expects <code>public.vja</code> at relation version <code>1</code></li><li>the query expects <code>public.vjb</code> at relation version <code>1</code></li><li>if either side no longer satisfies that contract, the query should not silently continue as if nothing changed</li></ul><p>That is why &quot;version binding&quot; is a better phrase here than &quot;version syntax.&quot; It is about explicit version control at the query boundary.</p><h2 id="why-version-binding-exists" tabindex="-1">Why version binding exists <a class="header-anchor" href="#why-version-binding-exists" aria-label="Permalink to &quot;Why version binding exists&quot;">​</a></h2><p>Most schema drift bugs are painful because they fail too late:</p><ul><li>a query still parses</li><li>a deployment still boots</li><li>but the semantics the application assumed are no longer true</li></ul><p>Version binding gives you a way to express:</p><blockquote><p>&quot;This query is coupled to this relation version. If the storage side has moved, fail visibly.&quot;</p></blockquote><h2 id="what-version-binding-is-not" tabindex="-1">What version binding is not <a class="header-anchor" href="#what-version-binding-is-not" aria-label="Permalink to &quot;What version binding is not&quot;">​</a></h2><p>This point is critical.</p><p>Version binding is <strong>not</strong> the same thing as historical row snapshotting.</p><p>It does <strong>not</strong> mean:</p><ul><li>&quot;show me the rows as they were when version 3 existed&quot;</li></ul><p>It means:</p><ul><li>&quot;run this query only if the relation version assumptions are satisfied&quot;</li></ul><p>For historical replay, use FlashQL&#39;s point-in-time boot support with <code>versionStop</code>.</p><h2 id="version-binding-vs-point-in-time-replay" tabindex="-1">Version binding vs point-in-time replay <a class="header-anchor" href="#version-binding-vs-point-in-time-replay" aria-label="Permalink to &quot;Version binding vs point-in-time replay&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Feature</th><th style="text-align:left;">What it means</th></tr></thead><tbody><tr><td style="text-align:left;">version binding in a query</td><td style="text-align:left;">&quot;this query assumes these relation versions&quot;</td></tr><tr><td style="text-align:left;"><code>versionStop</code> at boot</td><td style="text-align:left;">&quot;boot the local engine at this historical relation-version boundary&quot;</td></tr></tbody></table><p>These features complement each other, but they are not interchangeable.</p><h2 id="flashql-specific-support" tabindex="-1">FlashQL-specific support <a class="header-anchor" href="#flashql-specific-support" aria-label="Permalink to &quot;FlashQL-specific support&quot;">​</a></h2><p>Version binding is a FlashQL-oriented capability today because it depends on relation-version knowledge inside the local storage/runtime layer.</p><p>You will most commonly encounter it in:</p><ul><li>FlashQL queries</li><li>FlashQL joins</li><li>FlashQL historical/branching workflows</li></ul><h2 id="example-bind-and-then-boot-historically" tabindex="-1">Example: bind and then boot historically <a class="header-anchor" href="#example-bind-and-then-boot-historically" aria-label="Permalink to &quot;Example: bind and then boot historically&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.snap_tbl@=1</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>In that shape:</p><ul><li><code>versionStop</code> chooses the historical replay boundary</li><li><code>@=1</code> asserts the query&#39;s relation-version expectation</li></ul><h2 id="when-to-reach-for-version-binding" tabindex="-1">When to reach for version binding <a class="header-anchor" href="#when-to-reach-for-version-binding" aria-label="Permalink to &quot;When to reach for version binding&quot;">​</a></h2><p>Use it when:</p><ul><li>you care about schema/version safety more than silent compatibility</li><li>you are building version-aware local apps on FlashQL</li><li>you want joins to assert compatibility across multiple versioned relations</li></ul><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="/flashql">FlashQL</a></li><li><a href="/flashql/lang">FlashQL Language Reference</a></li><li><a href="/docs/query-api">Query Interface</a></li></ul>`,49)])])}const y=a(l,[["render",t]]);export{u as __pageData,y as default};
